    return []

solution:
def sorted_squares(a):
    n = len(a)
    res = [0] * n
    lo, hi = 0, n - 1
    for i in range(n - 1, -1, -1):
        if abs(a[lo]) > abs(a[hi]):
            res[i] = a[lo] * a[lo]
            lo += 1
        else:
            res[i] = a[hi] * a[hi]
            hi -= 1
    return res

